from llama_index.core.indices import VectorStoreIndex

from functools import wraps
import requests

def auth_middleware(query_engine):
    @wraps(query_engine.query)
    def wrapped_query(*args, **kwargs):
        # Refresh token if expired
        if not validate_token():
            refresh_access_token()
        return query_engine.query(*args, **kwargs)
    query_engine.query = wrapped_query
    return query_engine

def validate_token():
    response = requests.get('https://api.example.com/validate', 
                           headers={'Authorization': f'Bearer {get_token()}'},
                           timeout=5)
    return response.status_code == 200

def refresh_access_token():
    # Implementation depends on your auth provider
    token = requests.post('https://auth.example.com/token', 
                         json={'refresh_token': get_refresh_token()}).json()
    save_token(token['access_token'])

