def secure_tool_wrapper(func):
    @wraps(func)
    def wrapper(**kwargs):
        # Inject auth from current user context
        user_context = get_current_user_context()
        kwargs['headers'] = {
            'Authorization': f'Bearer {user_context["token"]}',
            'X-Tenant-ID': user_context['tenant_id']
        }
        kwargs['timeout'] = 30
        return func(**kwargs)
    return wrapper

